func prodFormTitle(p *domain.Product) string {
	if p == nil {
		return "New Product"
	}
	return "Edit " + p.Name
}

func prodFormSubtitle(p *domain.Product) string {
	if p == nil {
		return "Add a new product to your catalog"
	}
	return "Update product details"
}

func prodFormSignals(p *domain.Product) string {
	type sig struct {
		Name          string `json:"name"`
		Description   string `json:"description"`
		ProductType   string `json:"productType"`
		PriceAmount   string `json:"priceAmount"`
		PriceCurrency string `json:"priceCurrency"`
		BillingPeriod string `json:"billingPeriod"`
	}
	if p == nil {
		b, _ := json.Marshal(sig{ProductType: "internet", PriceCurrency: "EUR", BillingPeriod: "monthly"})
		return string(b)
	}
	b, _ := json.Marshal(sig{
		Name:          p.Name,
		Description:   p.Description,
		ProductType:   string(p.Type),
		PriceAmount:   p.Price.DisplayAmount(),
		PriceCurrency: p.Price.Currency,
		BillingPeriod: string(p.BillingPeriod),
	})
	return string(b)
}

